mapper.select:
SELECT E.EXPENSE_NO, E.APT_CMPLEX_NO, E.EXPENSE_YR, E.EXPENSE_MM, E.EXPENSE_AMT, E.EXPENSE_CD, C.CODE_NAME AS EXPENSE_CD_NM, C.CODE_CONTENT AS EXPENSE_CD_CONTENT, E.EXPENSE_CN, E.REG_DT, E.MDF_DT, E.RMRK_CN, E.ATCH_FILE_ID FROM EXPENSE E LEFT JOIN COMMON_CODE C ON C.GROUP_CODE_NO = 'EXPN_CD' AND C.CODE_NO_CD = E.EXPENSE_CD AND C.USE_YN = 'Y' WHERE E.APT_CMPLEX_NO = #{aptCmplexNo} AND E.EXPENSE_YR = #{expenseYr} AND E.EXPENSE_MM = #{expenseMm}
AND E.EXPENSE_CD = #{expenseCd}
ORDER BY C.SORT_ORDER ASC, E.REG_DT DESC

SELECT NVL(SUM(E.EXPENSE_AMT), 0)
FROM EXPENSE E
WHERE E.APT_CMPLEX_NO = #{aptCmplexNo}
AND E.EXPENSE_YR = #{expenseYr}
AND E.EXPENSE_MM = #{expenseMm}


    AND E.EXPENSE_CD = #{expenseCd}

SELECT COUNT(*)
FROM EXPENSE E
WHERE E.APT_CMPLEX_NO = #{aptCmplexNo}
AND E.EXPENSE_YR = #{expenseYr}
AND E.EXPENSE_MM = #{expenseMm}
AND E.EXPENSE_CD = #{expenseCd}



    AND E.EXPENSE_NO != #{expenseNo}

mapper.delete:
DELETE FROM EXPENSE
WHERE EXPENSE_NO = #{expenseNo}
  AND APT_CMPLEX_NO = #{aptCmplexNo}
